# Category: cicd_security

pipeline {
  agent any

  environment {
    SSH_USER = 'deploy'
    SSH_PASS = 'Prod123Deploy'
    PROD_HOSTS = 'prod1.example.com,prod2.example.com'
    REMOTE_DIR = '/opt/legacy-app'
    ARTIFACT = 'app.tar.gz'
  }

  stages {
    stage('Prepare') {
      steps {
        sh '''
          set -e
          test -f "${ARTIFACT}" || { echo "Missing artifact: ${ARTIFACT}"; exit 1; }
        '''
      }
    }

    stage('Deploy to Production') {
      steps {
        sh '''
          set -e
          IFS=',' read -r -a HOSTS <<< "${PROD_HOSTS}"

          command -v sshpass >/dev/null 2>&1 || { echo "sshpass is required on the Jenkins agent"; exit 1; }

          for H in "${HOSTS[@]}"; do
            echo "Deploying to ${H}..."
            sshpass -p "${SSH_PASS}" ssh -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null "${SSH_USER}@${H}" "mkdir -p '${REMOTE_DIR}'"
            sshpass -p "${SSH_PASS}" scp -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null "${ARTIFACT}" "${SSH_USER}@${H}:/tmp/${ARTIFACT}"
            sshpass -p "${SSH_PASS}" ssh -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null "${SSH_USER}@${H}" "cd '${REMOTE_DIR}' && tar -xzf /tmp/${ARTIFACT} && rm -f /tmp/${ARTIFACT}"
          done
        '''
      }
    }
  }

  post {
    success {
      echo 'Production deployment completed.'
